INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Transformation de l''organisation commerciale par l''IA', 'Formation sur l’intégration de l’IA dans les processus commerciaux.', 4, 300000.00, 'entreprise', '2026-06-10', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Compréhension du rôle stratégique de l’IA dans le commerce\n• Optimisation des processus commerciaux grâce aux outils IA\n• Amélioration de la gestion de la relation client (CRM intelligent)\n• Développement de stratégies marketing et de prospection automatisées\n• Meilleure prise de décision grâce aux données et à l’analyse prédictive\n• Anticipation des enjeux éthiques et réglementaires liés à l’IA\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre l’impact de l’IA sur le commerce et la vente, identifier les processus commerciaux optimisables, intégrer des outils IA dans la relation client et le marketing, développer une stratégie commerciale innovante et évaluer les performances commerciales avec l’IA.\n\n--- PRÉREQUIS ---\nConnaissances de base en gestion commerciale et marketing. Une familiarité avec les outils numériques est recommandée.\n\n--- CONTENU ---\nModule 1 : Introduction à l’IA et son impact sur le commerce\nModule 2 : Analyse et optimisation des processus commerciaux par l’IA\nModule 3 : IA et gestion de la relation client (CRM)\nModule 4 : IA pour la prospection et le marketing digital\nModule 5 : Pilotage commercial et prise de décision basée sur l’IA\nModule 6 : Gouvernance, éthique et limites de l’IA dans le commerce\nModule 7 : Plan d’action et transformation organisationnelle\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nDirecteurs commerciaux, responsables marketing, chefs d’entreprise, consultants en stratégie, managers souhaitant intégrer l’IA dans leurs pratiques commerciales.\n\n--- MÉTHODES ---\nExposés interactifs, études de cas réels, ateliers pratiques, démonstrations d’outils IA, discussions collectives et simulations.\n\n--- SUPPORTS ---\nCRM intelligents, outils de marketing digital, logiciels d’analyse prédictive, plateformes IA pour prospection et segmentation, supports PDF et tableaux de bord interactifs.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
